	@Test
	void canonicalMessageIsInvariantAcrossEquivalentSubsetConstructionOrder() {
		IRI p1 = iri("p1");
		IRI p2 = iri("p2");
		IRI p3 = iri("p3");
		StoreSynopsis synopsis = synopsis(List.of(
				triple("s0", p1, "x0"),
				triple("s1", p1, "x1"),
				triple("x0", p2, "y0"),
				triple("x1", p2, "y0"),
				triple("y0", p3, "z0")));

		StatementPattern a = pattern("s", p1, "x");
		StatementPattern b = pattern("x", p2, "y");
		StatementPattern c = pattern("y", p3, "z");

		MessagePassingJoinPlanner firstPlanner = new MessagePassingJoinPlanner(
				adapt(synopsis, List.of(a, b, c)).orElseThrow());
		MessagePassingJoinPlanner secondPlanner = new MessagePassingJoinPlanner(
				adapt(synopsis, List.of(b, a, c)).orElseThrow());

		MessagePassingJoinPlanner.Message first = firstPlanner.canonicalMessage(0b11L, "x");
		MessagePassingJoinPlanner.Message second = secondPlanner.canonicalMessage(0b11L, "x");

		assertEquals("x", first.variable());
		assertEquals(first.variable(), second.variable());
		assertEquals(sketchValues(first.sketch()), sketchValues(second.sketch()),
				"Canonical messages should not depend on factor construction order");
	}

	@Test
	void dynamicProgrammingChoosesSelectiveChainEndFirst() {
		IRI p1 = iri("p1");
		IRI p2 = iri("p2");
		IRI p3 = iri("p3");
		List<TripleData> statements = new ArrayList<>();
		for (int i = 0; i < 100; i++) {
			statements.add(triple("s" + i, p1, "x" + i));
		}
		for (int i = 0; i < 30; i++) {
			statements.add(triple("x" + i, p2, "y" + i));
		}
		statements.add(triple("y0", p3, "z0"));

		StatementPattern a = pattern("s", p1, "x");
		StatementPattern b = pattern("x", p2, "y");
		StatementPattern c = pattern("y", p3, "z");

		Optional<JoinOrderPlanner.JoinOrderPlan> plan = new MessagePassingJoinPlanner(
				adapt(synopsis(statements), List.of(a, b, c)).orElseThrow())
				.plan(JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING);

		assertTrue(plan.isPresent(), "Expected DP planner to find a selective chain order");
		assertEquals(List.of(c, b, a), plan.get().getOrderedArgs(),
				"DP should start from the narrow chain end and expand inward");
	}

