	private static Optional<PatternSynopsisAdapter.SupportedQuery> adapt(StoreSynopsis synopsis, List<TupleExpr> args) {
		return new PatternSynopsisAdapter(synopsis, (filter, pattern) -> 1.0d).adapt(args, Set.of());
	}

	private static StoreSynopsis synopsis(List<TripleData> statements) {
		StoreSynopsis.Builder builder = new StoreSynopsis.Builder(NOMINAL_ENTRIES, SEED);
		for (TripleData statement : statements) {
			builder.addStatement(fingerprint(statement.subject().stringValue()),
					fingerprint(statement.predicate().stringValue()),
					fingerprint(statement.object().stringValue()),
					fingerprint(statement.context().stringValue()));
		}
		return builder.build();
	}

	private static Map<Long, Double> sketchValues(ArrayOfDoublesCompactSketch sketch) {
		Map<Long, Double> values = new LinkedHashMap<>();
		ArrayOfDoublesSketchIterator iterator = sketch.iterator();
		while (iterator.next()) {
			values.put(iterator.getKey(), iterator.getValues()[0]);
		}
		return values;
	}

	private static StatementPattern pattern(String subjectVar, IRI predicate, String objectVar) {
		return new StatementPattern(Var.of(subjectVar), Var.of(predicate.getLocalName(), predicate), Var.of(objectVar));
	}

	private static TripleData triple(String subject, IRI predicate, String object) {
		return new TripleData(iri(subject), predicate, iri(object));
	}

	private static IRI iri(String localName) {
		return VF.createIRI("urn:" + localName);
	}

	private static long fingerprint(String value) {
		return SketchFingerprint.valueFingerprint(value);
	}

	private record TripleData(IRI subject, IRI predicate, IRI object, IRI context) {
		private TripleData(IRI subject, IRI predicate, IRI object) {
			this(subject, predicate, object, iri("defaultContext"));
		}
	}
